      options: [{ id: `A`, text: `p = 0.92(3,000)<sup>x</sup>` }, { id: `B`, text: `p = 1.08(3,000)<sup>x</sup>` }, { id: `C`, text: `p = 3,000(0.92)<sup>x</sup>` }, { id: `D`, text: `p = 3,000(1.08)<sup>x</sup>` }],
